const content = $input.all()[0].json.choices?.[0]?.message?.content || '{}';
try {
  return [{ json: JSON.parse(content) }];
} catch {
  return [{ json: { severity: 'medium', category: 'unknown', isAutoFixable: false, summary: '분석 실패', fixInstructions: null } }];
}

